  ('aboriginal-57f41407-moex-00116', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '關於上訴第二審，下列敘述何者錯誤？', '["得對於第一審之終局判決為之", "應向原第一審法院提出上訴狀", "應於第一審判決送達後20日之不變期間內為之", "除有特別規定外，當事人得提出新攻擊或防禦方法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00117', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '關於訴及上訴之撤回，下列敘述何者正確？', '["原告於第三審進行中，不得撤回起訴", "反訴因本訴之撤回而失其效力", "於本案終局判決後將訴撤回者，仍得提起同一訴訟", "上訴人於終局判決前，得將上訴撤回"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00118', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '關於上訴第三審，下列敘述何者正確？', '["上訴之聲明，得為變更或擴張", "上訴之聲明，不得減縮", "被上訴人不得為附帶上訴", "被上訴人得提起反訴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00119', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '就第二審法院所為之訴外判決，經受不利判決之當事人上訴，第三審法院就該部分應為如何之判決？', '["廢棄原判決，自為判決", "廢棄原判決，發回原法院", "廢棄原判決，發交其他同級法院", "廢棄原判決"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00120', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '關於再審，下列敘述何者錯誤？', '["當事人提起再審之訴後，得於再審之不變期間內，追加其他再審理由", "當事人以確定判決適用法規顯有錯誤為由，對之提起再審之訴，其再審之不變期間均應自該判決確 定時起算", "再審之訴，法院認無再審理由，判決駁回後，不得以同一事由，對於原確定判決或駁回再審之訴之 確定判決，更行提起再審之訴", "對於第三審法院以上訴不合法而駁回上訴之裁定，均不得以發現未經斟酌之證物或得使用該證物為 理由，聲請再審"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00121', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '關於支付命令之異議，下列敘述何者錯誤？', '["債務人得於支付命令送達後20日之不變期間內，向發命令之法院提出異議", "債務人對於支付命令提出異議，須附理由", "債務人對於支付命令於法定期間合法提出異議者，支付命令於異議之範圍內失其效力，以債權人支 付命令之聲請，視為起訴或聲請調解", "連帶債務人中1人或數人以非基於個人關係之事由提出異議，並有理由者，其異議之效力及於全體"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL)
